// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: { day: string; icon: string; high: number; low: number }[]; // 5-day forecast array
}

function useComponent(props: Props) {
  const getIcon = useCallback((condition: string) => {
    const cond = condition.toLowerCase();
    if (cond.includes('sun')) return 'sun';
    if (cond.includes('cloud')) return 'cloud';
    if (cond.includes('rain')) return 'rain';
    return 'cloud';
  }, []);

  return { getIcon };
}

export default function Component(props: Props) {
  const { getIcon } = useComponent(props);

  return (
    <Card padding={24} shadow="md" style={{ maxWidth: 400 }}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>{props.city}</Heading>
          <Badge variant="primary">{props.unit}</Badge>
        </Row>

        <Stack align="center" gap={4}>
          <Heading level={1} color="var(--ggui-color-primary-600)">{props.temperature}°</Heading>
          <Text variant="bodyLarge">{props.condition}</Text>
        </Stack>

        <Row justify="around">
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="label">{props.humidity}%</Text>
          </Box>
          <Box>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text variant="label">{props.windSpeed} km/h</Text>
          </Box>
        </Row>

        <Divider margin={8} />

        <Row justify="between">
          {props.forecast.map((f, i) => (
            <Box
              as={Hoverable}
              key={i}
              hoverStyle={{ background: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-md)' }}
              padding={8}
            >
              <Stack align="center" gap={4}>
                <Text variant="caption">{f.day}</Text>
                <Icon name={getIcon(f.icon)} size={20} color="var(--ggui-color-onSurfaceVariant)" />
