import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const moveTask = (taskId: string, columnId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: columnId } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'MOVE_TASK', taskId, columnId });
  };

  const addTask = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
      dueDate: new Date().toISOString().split('T')[0]
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setIsAdding(null);
    handleTaskUpdate({ type: 'ADD_TASK', ...newTask });
  };

  const editTask = (taskId: string, title: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, title } : t));
    handleTaskUpdate({ type: 'EDIT_TASK', taskId, title });
  };

  return { tasks, isAdding, setIsAdding, editingTaskId, setEditingTaskId, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, moveTask, addTask, editTask };
}

export default function Component(props: Props) {
  const { tasks, isAdding, setIsAdding, editingTaskId, setEditingTaskId, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, moveTask, addTask, editTask } = useComponent(props);
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Stack direction="horizontal" gap={8}>
            <Badge variant="secondary">{totalTasks} tasks</Badge>
            <Badge variant="success">{completedTasks} completed</Badge>
          </Stack>
        </Row>
        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
          {props.columns.map(col => (
            (() => {
              const colTasks = tasks.filter(t => t.column === col.id);
              return (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
              <Stack gap={12}>
                <Row justify="between" align="center">
                  <Heading level={3} color="var(--ggui-color-onSurfaceVariant)">{col.name}</Heading>
                  <Badge variant="secondary">{colTasks.length}</Badge>
                </Row>
                <Stack as="ul" gap={8} style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                  {colTasks.map(task => (
                  <Card as="li" key={task.id} padding={12} shadow="sm" role="listitem" onDoubleClick={() => setEditingTaskId(task.id)}>
                    <Stack gap={8}>
                      {editingTaskId === task.id ? (
                        <Input 
                          autoFocus 
                          aria-label="Edit task title"
                          value={task.title} 
                          onChange={(val) => editTask(task.id, val)} 
                          onKeyDown={(e) => { if (e.key === 'Enter') setEditingTaskId(null); }}
                          onBlur={() => setEditingTaskId(null)}
                        />
                      ) : (
                        <Text variant="bodySmall" style={{ fontWeight: 500 }}>{task.title}</Text>
                      )}
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Due: {task.dueDate}</Text>
                      <Row justify="between" align="center">
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'primary'}>{task.priority}</Badge>
                        <Row gap={4} align="center">
                          <Avatar name={task.assignee} size={24} />
                          <Dropdown aria-label={`Move task ${task.title}`} trigger={<Button variant="ghost" size="xs"><Icon name="chevron-down" size={16} /></Button>} value={col.id} onChange={(nextCol) => moveTask(task.id, nextCol)} options={props.columns.map(c => ({ value: c.id || '', label: c.name || '' }))} />
                        </Row>
                      </Row>
                    </Stack>
                  </Card>
                  ))}
                </Stack>
                {isAdding === col.id ? (
                  <Stack gap={8}>
                    <Input aria-label="New task title" placeholder="Enter task title..." value={newTaskTitle} onChange={setNewTaskTitle} />
                    <Select label="Set Priority" value={newTaskPriority} onChange={setNewTaskPriority} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
                    <Row gap={8}>
                      <Button size="sm" onClick={() => addTask(col.id || '')}>Save Task</Button>
                      <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                    </Row>
                  </Stack>
                ) : (
                  <Button variant="ghost" onClick={() => setIsAdding(col.id || null)}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
              );
            })()
          ))}
        </CardGrid>
      </Stack>
    </Container>
  );
}

