import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);
  const filtered = useMemo(() => props.elements.filter(e => 
    e.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    e.symbol.toLowerCase().includes(searchQuery.toLowerCase())
  ), [props.elements, searchQuery]);

  const getColor = (cat: string) => {
    const map: Record<string, string> = {
      'Noble Gas': 'var(--ggui-color-info-600, #0891b2)',
      'Halogen': 'var(--ggui-color-warning-600, #d97706)',
      'Alkali Metal': 'var(--ggui-color-error-600, #dc2626)',
      'Transition Metal': 'var(--ggui-color-primary-600, #0284c7)',
      'Other': 'var(--ggui-color-neutral-400, #9ca3af)',
    };
    return map[cat] || map['Other'];
  };

  return { searchQuery, setSearchQuery, selected, setSelected, filtered, categories, getColor };
}

export default function Component(props: Props) {
  const { searchQuery, setSearchQuery, selected, setSelected, filtered, categories, getColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={32}>
      <Stack gap={32}>
        <Heading level={2}>Periodic Table</Heading>
        <SearchField value={searchQuery} onChange={setSearchQuery} placeholder="Filter elements by name or symbol..." />
        <Card padding={16} radius="md" border={true} style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--ggui-spacing-2)' }}>
          <Text variant="label" style={{ alignSelf: 'center', marginRight: 'var(--ggui-spacing-2)' }}>Legend:</Text>
          {categories.map(cat => (
            <Badge key={cat} variant="default" style={{ background: getColor(cat), color: 'white', fontWeight: '500' }}>{cat}</Badge>
          ))}
        </Card>
        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, minmax(50px, 1fr))', 
          gridTemplateRows: 'repeat(7, 60px)',
          gap: 'var(--ggui-spacing-1)', 
          overflowX: 'auto', 
          padding: 'var(--ggui-spacing-2)',
          background: 'var(--ggui-color-surfaceVariant)',
          borderRadius: 'var(--ggui-shape-radius-md)'
        }}>
          {props.elements.map(e => {
            const isFiltered = searchQuery && !filtered.includes(e);
            return (
              <Card
                key={e.symbol}
                as={Clickable}
                onClick={() => setSelected(e)} 
                role="button"
                aria-label={`Select ${e.name} (${e.symbol})`}
                padding={8}
                style={{ 
                  gridRow: e.row, gridColumn: e.col, minHeight: 60,
                  background: getColor(e.category), 
                  color: 'white',
                  opacity: isFiltered ? 0.3 : 1, 
                  border: selected?.symbol === e.symbol ? '2px solid white' : '1px solid rgba(255,255,255,0.3)',
                  transition: 'all 200ms ease', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
                }}
              >
                <Text variant="caption" style={{ fontSize: '9px', alignSelf: 'flex-start', color: 'white' }}>{e.atomicNumber}</Text>
                <Text variant="label" style={{ fontWeight: 'bold', fontSize: '14px', color: 'white' }}>{e.symbol}</Text>
              </Card>
            );
          })}
        </Box>
        {searchQuery && filtered.length === 0 && (
            <Alert variant="info">No elements match your search.</Alert>
        )}
        {selected && (
          <Modal open={true} onClose={() => setSelected(null)} title={`${selected.name} (${selected.symbol})`}>
              <Stack gap={16}>
                  <Badge variant="default" style={{ background: getColor(selected.category), color: 'white', width: 'fit-content', borderRadius: 'var(--ggui-shape-radius-full)' }}>{selected.category}</Badge>
                  <Divider />
                  <Stack direction="vertical" gap={8}>
                    <Text variant="bodySmall">Atomic Number: <strong>{selected.atomicNumber}</strong></Text>
                    <Text variant="bodySmall">Atomic Weight: <strong>{selected.atomicWeight.toFixed(3)}</strong></Text>
                  </Stack>
              </Stack>
          </Modal>
        )}
      </Stack>
    </Container>
  );
}

