import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: { label: string; value: string }[]; reviews: { id: string; author: string; rating: number; text: string; date: string }[] };
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity(q => Math.max(1, Math.min(props.product.stock, q + delta)));
  }, [props.product.stock]);

  return {
    quantity,
    activeTab,
    setActiveTab,
    handleQuantityChange,
    handleAddToCart: () => handleAddToCart({ productId: props.product.id, quantity })
  };
}

export default function Component(props: Props) {
  const { quantity, activeTab, setActiveTab, handleQuantityChange, handleAddToCart } = useComponent(props);
  const { product } = props;

  const renderStars = (rating: number) => (
    <Row gap={2}>
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon key={star} size={16} color="var(--ggui-color-warning-500, #f59e0b)"><svg viewBox="0 0 24 24" fill={star <= Math.round(rating) ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg></Icon>
      ))}
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" aria-label={`${product.reviewCount} reviews`}>({product.reviewCount})</Text>
    </Row>
  );

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Row direction="horizontal" gap={48} align="start" wrap>
          <Box background="var(--ggui-color-surfaceVariant)" padding={64} borderRadius="lg" style={{ flex: '1 1 400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
             <Heading level={2}>{product.name}</Heading>
          </Box>
          <Stack gap={24} style={{ flex: '1 1 400px' }}>
            <Heading level={1}>{product.name}</Heading>
            {renderStars(product.rating)}
            <Text variant="bodyLarge" size="2xl" weight="bold">{product.currency}{product.price.toFixed(2)}</Text>
            <Box>
              <Badge variant={product.stock > 0 ? 'success' : 'error'} size="lg">
                {product.stock > 0 ? (product.stock < 5 ? `Low Stock (${product.stock} available)` : 'In Stock') : 'Out of Stock'}
              </Badge>
            </Box>
            <Card padding={24} shadow="none" border radius="md">
              <Stack gap={16}>
                <Row gap={4} align="center">
                  <Button variant="outline" size="sm" onClick={() => handleQuantityChange(-1)} aria-label="Decrease quantity"><Icon name="minus" size={16}/></Button>
                  <Text variant="body" weight="medium" style={{ minWidth: 32, textAlign: 'center' }}>{quantity}</Text>
                  <Button variant="outline" size="sm" onClick={() => handleQuantityChange(1)} aria-label="Increase quantity"><Icon name="plus" size={16}/></Button>
                  <Spacer size="flex" />
                  <Button variant="primary" size="md" disabled={product.stock === 0} onClick={handleAddToCart}>Add to Cart</Button>
                </Row>
                {product.stock === 0 && <Text variant="caption" color="var(--ggui-color-error-500)">Out of stock</Text>}
              </Stack>
            </Card>
          </Stack>
        </Row>
        <Tabs 
          items={[
            { key: 'description', label: 'Description', content: <Box paddingY={16}><Text>{product.description}</Text></Box> },
            { key: 'specs', label: 'Specifications', content: <Box paddingY={16}><Table columns={[{ key: 'label', header: 'Feature' }, { key: 'value', header: 'Details' }]} data={product.specifications} bordered /></Box> },
            { key: 'reviews', label: 'Reviews', content: <Box paddingY={16}><Stack gap={16}>{product.reviews.map(r => (
              <Card key={r.id} padding={16} shadow="sm">
                <Stack gap={8}>
                  <Row justify="between"><Text variant="label">{r.author}</Text><Text variant="caption">{new Date(r.date).toLocaleDateString()}</Text></Row>
                  {renderStars(r.rating)}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{r.text}</Text>
                </Stack>
              </Card>
            ))}</Stack></Box> }
          ]}
          activeKey={activeTab}
          onChange={setActiveTab}
        />
      </Stack>
    </Container>
  );
}

