import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile);

  const validateEmail = useCallback((email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email), []);

  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      return !!(formData.name.trim() && validateEmail(formData.email));
    }
    if (currentStep === 2) {
      return !!formData.role;
    }
    return true;
  }, [currentStep, formData]);

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleNext = () => {
    if (isStepValid) {
      if (currentStep < 3) setCurrentStep(currentStep + 1);
      else handleComplete(formData);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  return { currentStep, handleBack, formData, updateField, isStepValid, handleNext, handleComplete, validateEmail };
}

export default function Component(props: Props) {
  const { currentStep, handleBack, formData, updateField, isStepValid, handleNext, handleComplete, validateEmail } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Welcome to Onboarding</Heading>
          <Progress value={(currentStep / 3) * 100} />
          <Text variant="bodySmall">Step {currentStep} of 3</Text>
        </Stack>

        <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius="md">
          {currentStep === 1 && (
            <Stack gap={16}>
              <FormField label="Full Name" required><Input value={formData.name} placeholder="Jane Doe" onChange={(v) => updateField('name', v)} /></FormField>
              <FormField label="Email" required error={formData.email && !validateEmail(formData.email) ? 'Invalid email format' : ''}><Input type="email" value={formData.email} placeholder="jane@example.com" onChange={(v) => updateField('email', v)} /></FormField>
              <Text variant="label">Select Avatar</Text>
              <Row gap={16}>
                {props.avatarOptions.map(emoji => (
                  <Box 
                    as={Clickable} 
                    key={emoji} 
                    role="button"
                    aria-label={`Choose avatar ${emoji}`}
                    aria-pressed={formData.avatar === emoji}
                    padding={12} 
                    background={formData.avatar === emoji ? 'var(--ggui-color-primary-200)' : 'var(--ggui-color-surface)'} 
                    borderRadius="md" 
                    onClick={() => updateField('avatar', emoji)}
                  >
                    <Text size="xl">{emoji}</Text>
                  </Box>
                ))}
              </Row>
            </Stack>
          )}
          {currentStep === 2 && (
            <Stack gap={16}>
              <FormField label="Role" required><Select value={formData.role} onChange={(v) => updateField('role', v)} options={props.roleOptions.map(r => ({ value: r, label: r }))} placeholder="Select a role" /></FormField>
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}
          {currentStep === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Review</Heading>
              <Stack gap={12} as="dl">
                <Row justify="between"><Text variant="label" as="dt">Name</Text><Text as="dd">{formData.name}</Text></Row>
                <Row justify="between"><Text variant="label" as="dt">Email</Text><Text as="dd">{formData.email}</Text></Row>
                <Row justify="between"><Text variant="label" as="dt">Role</Text><Text as="dd">{formData.role}</Text></Row>
                <Row justify="between"><Text variant="label" as="dt">Avatar</Text><Text as="dd">{formData.avatar}</Text></Row>
              </Stack>
            </Stack>
          )}
        </Box>

        <Row justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={currentStep === 1}>Back</Button>
          <Button variant="primary" disabled={!isStepValid} onClick={handleNext}>
            {currentStep === 3 ? 'Complete Setup' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}
